"/* ==========================================================================
   Greens Global - Master Dashboard CSS
   ========================================================================== */

/* Design Tokens & Theme Variables */
:root {
  /* Light Mode Color Variables */
  --bg-primary: #ffffff;
  --bg-secondary: #f8f9fa;
  --bg-sidebar: #f8f9fa;
  --bg-card: #ffffff;
  --border-color: #eaecef;
  --border-hover: #dcdfe3;

  --text-primary: #111827;
  --text-secondary: #4b5563;
  --text-muted: #9ca3af;

  --sidebar-hover-bg: #eaecef;
  --sidebar-active-bg: #eaecef;
  --sidebar-active-text: #111827;

  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.05), 0 2px 4px -1px rgba(0, 0, 0, 0.03);
  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.05), 0 4px 6px -2px rgba(0, 0, 0, 0.02);

  /* Colored Accents (Base Hue, Saturation, Lightness) */
  --color-blue: 215, 100%, 50%;
  --color-orange: 24, 95%, 50%;
  --color-green: 142, 70%, 45%;
  --color-purple: 271, 80%, 55%;
  --color-red: 350, 80%, 55%;
  --color-gold: 42, 95%, 48%;

  /* Transitions */
  --transition-fast: 0.15s ease;
  --transition-normal: 0.25s ease;
  --transition-slow: 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

[data-theme="dark"] {
  /* Dark Mode Color Variables */
  --bg-primary: #0b0f19;
  --bg-secondary: #111827;
  --bg-sidebar: #0e1320;
  --bg-card: #1f2937;
  --border-color: #374151;
  --border-hover: #4b5563;

  --text-primary: #f3f4f6;
  --text-secondary: #9ca3af;
  --text-muted: #6b7280;

  --sidebar-hover-bg: #1f2937;
  --sidebar-active-bg: #1f2937;
  --sidebar-active-text: #ffffff;

  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.2);
  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.2), 0 2px 4px -1px rgba(0, 0, 0, 0.1);
  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.3), 0 4px 6px -2px rgba(0, 0, 0, 0.15);
}

/* Global Reset & Base Styles */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

