  .sidebar {
    transform: translateX(-280px);
  }

  .sidebar.open {
    transform: translateX(0);
  }

  .sidebar-overlay {
    display: none;
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-color: rgba(0, 0, 0, 0.4);
    z-index: 95;
    backdrop-filter: blur(2px);
  }

  .sidebar-overlay.active {
    display: block;
