.sop-update-row:hover {
  border-color: var(--border-hover) !important;
  background-color: var(--bg-secondary);
}

/* Toggle Switch Styling */
.switch-container {
  position: relative;
  display: inline-block;
  width: 44px;
  height: 24px;
}

.switch-container input {
  opacity: 0;
  width: 0;
  height: 0;
}

.switch-slider {
  position: absolute;
  cursor: pointer;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-color: var(--border-color);
  transition: .3s;
  border-radius: 24px;
}

.switch-slider:before {
  position: absolute;
  content: "";
  height: 18px;
  width: 18px;
  left: 3px;
  bottom: 3px;
  background-color: white;
  transition: .3s;
  border-radius: 50%;
}

.switch-container input:checked + .switch-slider {
  background-color: #111827;
}

[data-theme="dark"] .switch-container input:checked + .switch-slider {
  background-color: #ffffff;
}

[data-theme="dark"] .switch-container input:checked + .switch-slider:before {
  background-color: #111827;
}

.switch-container input:checked + .switch-slider:before {
  transform: translateX(20px);
}

/* Responsive Styles */"

